module adder_32bit(
	input wire [31:0] num1,
	input wire [31:0] num2,
	output wire [31:0] sum
);  wire _n01 = num1[0] ^ num2[0];
  wire _c01 = num1[0] & num2[0];
  wire _n02 = num1[1] ^ num2[1] ^ _c01;
  wire _c02 = (num1[1] & num2[1]) | (num1[1] & _c01) | (num2[1] & _c01);
  wire _n03 = num1[2] ^ num2[2] ^ _c02;
  wire _c03 = (num1[2] & num2[2]) | (num1[2] & _c02) | (num2[2] & _c02);
  wire _n04 = num1[3] ^ num2[3] ^ _c03;
  wire _c04 = (num1[3] & num2[3]) | (num1[3] & _c03) | (num2[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};
endmodule
